import { useState, useEffect } from 'react';
import { db } from '../../firebase';
import { 
  collection, 
  onSnapshot, 
  doc,
  addDoc,
  updateDoc,
  deleteDoc,
  query,
  orderBy
} from 'firebase/firestore';
import { ERPBlock, Notification } from '../../types/appTypes';

export const useERPData = (onAddNotification: (n: Partial<Notification>) => void) => {
  const [erpBlocks, setErpBlocks] = useState<ERPBlock[]>([]);

  useEffect(() => {
    const q = query(collection(db, 'erp_blockages'), orderBy('timestamp', 'desc'));
    return onSnapshot(q, (snapshot) => {
      setErpBlocks(snapshot.docs.map(d => ({ id: d.id, ...d.data() } as ERPBlock)));
    });
  }, []);

  const onAddERPBlock = async (partNumber: string, qty: string, workplace: string) => {
    const user = localStorage.getItem('app_user') || 'Unknown';
    await addDoc(collection(db, 'erp_blockages'), {
      partNumber,
      quantity: qty,
      workplace,
      reportedBy: user,
      status: 'WAITING',
      timestamp: Date.now()
    });
  };

  const onUpdateERPBlockStatus = async (id: string, newStatus: 'RESOLVING' | 'READY') => {
    const block = erpBlocks.find(b => b.id === id);
    if (!block) return;

    const user = localStorage.getItem('app_user') || 'Admin';
    const updates: any = { status: newStatus };

    if (newStatus === 'READY') {
      updates.resolvedAt = Date.now();
      updates.resolvedBy = user;

      // Odoslanie notifikácie majstrovi (pôvodnému zadávateľovi)
      onAddNotification({
        partNumber: block.partNumber,
        reason: `MÔŽEŠ NAHRAŤ: Blokácia odpisov pre tento diel bola v EFACS odstránená.`,
        reportedBy: user,
        targetUser: block.reportedBy,
        timestamp: Date.now()
      });
    }

    await updateDoc(doc(db, 'erp_blockages', id), updates);
  };

  const onDeleteERPBlock = async (id: string) => {
    await deleteDoc(doc(db, 'erp_blockages', id));
  };

  return { erpBlocks, onAddERPBlock, onUpdateERPBlockStatus, onDeleteERPBlock };
};

import { useRef, useCallback, useEffect } from 'react';
import { useSystemData } from './data/useSystemData';
import { useMasterData } from './data/useMasterData';
import { useOperationsData } from './data/useOperationsData';
import { useTaskData } from './data/useTaskData';
import { useERPData } from './data/useERPData';
import { Role } from '../types/appTypes';

export const useFirestoreData = (isAuthenticated: boolean, currentUserRole: string) => {

  // 1. SYSTEM DATA (Users, Roles, Notifications)
  const systemData = useSystemData();
  const { roles, onAddNotification } = systemData;

  // 2. MASTER DATA (Parts, BOM, Workplaces, Sectors, Logistics)
  const masterData = useMasterData();

  // 3. OPERATIONS DATA (Breaks, Reasons)
  const operationsData = useOperationsData();

  // 4. PERMISSION HELPER
  const rolesRef = useRef<Role[]>([]);
  const currentUserRoleRef = useRef(currentUserRole);

  useEffect(() => { rolesRef.current = roles; }, [roles]);
  useEffect(() => { currentUserRoleRef.current = currentUserRole; }, [currentUserRole]);

  const checkPermissionRef = useCallback((permName: string) => {
      const currentRole = currentUserRoleRef.current;
      if (currentRole === 'ADMIN') return true;
      const r = rolesRef.current.find(ro => ro.name === currentRole);
      if (!r) return false;
      return r.permissions ? r.permissions.includes(permName) : false;
  }, []);

  // 5. TASK DATA
  const taskData = useTaskData(isAuthenticated, checkPermissionRef, onAddNotification);

  // 6. ERP BLOCKAGE DATA (New)
  const erpData = useERPData(onAddNotification);

  // 7. COMPOSE & RETURN
  return {
    ...systemData,
    ...masterData,
    ...operationsData,
    ...taskData,
    ...erpData
  };
};

