          )}

          {hasPermission('perm_tab_map') && (
            <button onClick={() => setActiveTab('map')} className={`whitespace-nowrap py-3 px-1 border-b-4 font-bold text-sm transition-colors ${activeTab === 'map' ? 'border-amber-500 text-amber-400' : 'border-transparent text-gray-400 hover:text-gray-200 hover:border-gray-500'}`}>{t('tab_map')}</button>
          )}

          {currentUserRole === 'ADMIN' && (
            <button onClick={() => setActiveTab('logs')} className={`whitespace-nowrap py-3 px-1 border-b-4 font-bold text-sm transition-colors ${activeTab === 'logs' ? 'border-cyan-500 text-cyan-400' : 'border-transparent text-gray-400 hover:text-gray-200 hover:border-gray-500'}`}>{t('tab_logs')}</button>
          )}

          {hasPermission('perm_tab_analytics') && (
            <button onClick={() => setActiveTab('analytics')} className={`whitespace-nowrap py-3 px-1 border-b-4 font-bold text-sm transition-colors ${activeTab === 'analytics' ? 'border-teal-500 text-teal-400' : 'border-transparent text-gray-400 hover:text-gray-200 hover:border-gray-500'}`}>{t('tab_analytics')}</button>
          )}

          {hasPermission('perm_tab_settings') && (
            <button onClick={() => setActiveTab('settings')} className={`relative whitespace-nowrap py-3 px-1 border-b-4 font-bold text-sm transition-colors ${activeTab === 'settings' ? 'border-teal-500 text-teal-400' : 'border-transparent text-gray-400 hover:text-gray-200 hover:border-gray-500'} ${counts.pendingRequests > 0 ? 'text-red-400' : ''}`}>{t('tab_settings')} {counts.pendingRequests > 0 && <span className="ml-1 sm:ml-2 bg-red-500 text-white text-xs rounded-full px-1.5 sm:px-2 py-0.5">{counts.pendingRequests}</span>}</button>
          )}

          {hasPermission('perm_tab_permissions') && (
            <button onClick={() => setActiveTab('permissions')} className={`whitespace-nowrap py-3 px-1 border-b-4 font-bold text-sm transition-colors ${activeTab === 'permissions' ? 'border-teal-500 text-teal-400' : 'border-transparent text-gray-400 hover:text-gray-200 hover:border-gray-500'}`}>{t('tab_permissions')}</button>
