import { useState, useEffect } from 'react';
import { db } from '../../firebase';
import { 
  doc, 
  onSnapshot, 
  updateDoc, 
  arrayUnion, 
  getDoc
} from 'firebase/firestore';
import { ERPBlock, Notification } from '../../types/appTypes';

export const useERPData = (onAddNotification: (n: Partial<Notification>) => void) => {
  const [erpBlocks, setErpBlocks] = useState<ERPBlock[]>([]);
  const docRef = doc(db, 'settings', 'erp_blockages');

  useEffect(() => {
    return onSnapshot(docRef, (snap) => {
      if (snap.exists()) {
        const data = snap.data();
        setErpBlocks(Array.isArray(data.items) ? data.items : []);
      } else {
        setErpBlocks([]);
      }
    });
  }, []);

  const onAddERPBlock = async (partNumber: string, qty: string) => {
    const user = localStorage.getItem('app_user') || 'Unknown';
    const newBlock: ERPBlock = {
      id: crypto.randomUUID(),
      partNumber,
      quantity: qty,
      workplace: '', // Odstránené podľa požiadavky, ponechané v type pre kompatibilitu
      reportedBy: user,
      status: 'WAITING',
      timestamp: Date.now()
    };

    await updateDoc(docRef, {
      items: arrayUnion(newBlock)
    });
  };

  const onUpdateERPBlockStatus = async (id: string, newStatus: 'RESOLVING' | 'READY', comment?: string) => {
    const snap = await getDoc(docRef);
    if (!snap.exists()) return;

    const items = [...(snap.data().items || [])];
    const idx = items.findIndex((b: ERPBlock) => b.id === id);
    if (idx === -1) return;

    const user = localStorage.getItem('app_user') || 'Admin';
    const block = items[idx];

    items[idx] = {
      ...block,
      status: newStatus,
      comment: comment || block.comment || '',
      resolvedAt: newStatus === 'READY' ? Date.now() : block.resolvedAt,
      resolvedBy: newStatus === 'READY' ? user : block.resolvedBy
    };

    if (newStatus === 'READY') {
      onAddNotification({
        partNumber: block.partNumber,
        reason: `MÔŽEŠ NAHRAŤ: Blokácia odstránená. ${comment ? `Pozn: ${comment}` : ''}`,
        reportedBy: user,
        targetUser: block.reportedBy,
        timestamp: Date.now()
      });
    }

    await updateDoc(docRef, { items });
  };

  const onDeleteERPBlock = async (id: string) => {
    const snap = await getDoc(docRef);
    if (!snap.exists()) return;
    const items = (snap.data().items || []).filter((b: ERPBlock) => b.id !== id);
    await updateDoc(docRef, { items });
  };

  const onDeleteAllERPBlocks = async () => {
    if (window.confirm('Naozaj vymazať celú históriu blokácií?')) {
        await updateDoc(docRef, { items: [] });
    }
  };

  return { erpBlocks, onAddERPBlock, onUpdateERPBlockStatus, onDeleteERPBlock, onDeleteAllERPBlocks };
};

import React, { useState, useEffect } from 'react';
import { ERPBlock } from '../../types/appTypes';
import { useLanguage } from '../LanguageContext';
import PartNumberInput from '../PartNumberInput';

declare var XLSX: any;

interface ProductionBlockagesTabProps {
    erpBlocks: ERPBlock[];
    parts: string[];
    onAddERPBlock: (part: string, qty: string) => Promise<void>;
    onUpdateERPBlockStatus: (id: string, status: 'RESOLVING' | 'READY', comment?: string) => Promise<void>;
    onDeleteERPBlock: (id: string) => Promise<void>;
    onDeleteAllERPBlocks: () => Promise<void>;
    hasPermission: (perm: string) => boolean;
    resolveName: (username?: string | null) => string;
}

const ProductionBlockagesTab: React.FC<ProductionBlockagesTabProps> = (props) => {
    const { t, language } = useLanguage();
    const [part, setPart] = useState('');
    const [qty, setQty] = useState('');
    const [currentTime, setCurrentTime] = useState(Date.now());

    // State pre komentár pred dokončením
    const [commentTargetId, setCommentTargetId] = useState<string | null>(null);
    const [tempComment, setTempComment] = useState('');

    useEffect(() => {
        const interval = setInterval(() => setCurrentTime(Date.now()), 30000);
        return () => clearInterval(interval);
    }, []);

    const handleReport = async () => {
        if (!part || !qty) {
            alert(t('fill_all_fields'));
            return;
        }
        await props.onAddERPBlock(part, qty);
        setPart(''); setQty('');
    };

    const handleExportExcel = () => {
        if (!props.erpBlocks.length) return;
        const data = props.erpBlocks.map(b => ({
            'Dátum': new Date(b.timestamp).toLocaleDateString('sk-SK'),
            'Čas': new Date(b.timestamp).toLocaleTimeString('sk-SK'),
            'Diel': b.partNumber,
            'Množstvo': b.quantity,
            'Hlásil': props.resolveName(b.reportedBy),
            'Stav': b.status,
            'Vybavil': props.resolveName(b.resolvedBy),
            'Komentár': b.comment || ''
        }));
        const ws = XLSX.utils.json_to_sheet(data);
        const wb = XLSX.utils.book_new();
        XLSX.utils.book_append_sheet(wb, ws, "ERP_Blokacie");
        XLSX.writeFile(wb, `ERP_Blokacie_${new Date().toISOString().slice(0,10)}.xlsx`);
    };

    const getAgeingMinutes = (timestamp: number) => Math.floor((currentTime - timestamp) / 60000);

    return (
        <div className="max-w-7xl mx-auto space-y-8 pb-20 animate-fade-in text-slate-200">
            {/* ACTION BAR */}
            <div className="flex justify-between items-center bg-slate-900/40 p-4 rounded-2xl border border-slate-800">
                <div className="flex gap-2">
                    <button onClick={handleExportExcel} className="bg-emerald-600/20 hover:bg-emerald-600/40 text-emerald-500 px-4 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest border border-emerald-500/30 transition-all flex items-center gap-2">
                        📊 EXPORT EXCEL
                    </button>
                    {props.hasPermission('perm_manage_db') && (
                        <button onClick={props.onDeleteAllERPBlocks} className="bg-red-900/20 hover:bg-red-900/40 text-red-500 px-4 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest border border-red-500/30 transition-all">
                            🗑️ VYMAZAŤ VŠETKO
                        </button>
                    )}
                </div>
                <div className="text-right">
                    <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest">AKTÍVNE BLOKÁCIE: {props.erpBlocks.filter(b => b.status !== 'READY').length}</span>
                </div>
            </div>

            {/* REPORT FORM (PRE MAJSTRA) */}
            {props.hasPermission('perm_tab_entry') && (
                <div className="bg-indigo-900/10 border-2 border-indigo-500/30 rounded-3xl p-6 shadow-xl ring-1 ring-indigo-500/20">
                    <h3 className="text-xl font-black text-indigo-400 mb-6 uppercase tracking-tighter flex items-center gap-2">
                        <span className="text-2xl">🚨</span> {t('erp_report_title')}
                    </h3>
                    <div className="grid grid-cols-1 md:grid-cols-3 gap-4 items-end">
                        <div className="md:col-span-1">
                            <label className="block text-[10px] font-black text-slate-500 uppercase tracking-widest mb-2">{t('erp_comp_label')}</label>
                            <PartNumberInput 
                                parts={props.parts} 
                                value={part} 
                                onPartSelect={(v) => setPart(v || '')} 
                                onInputChange={setPart}
                                placeholder="..."
                            />
                        </div>
                        <div>
                            <label className="block text-[10px] font-black text-slate-500 uppercase tracking-widest mb-2">{t('erp_qty_to_book')}</label>
                            <input 
                                type="number" 
                                value={qty} 
                                onChange={e => setQty(e.target.value)}
                                className="w-full h-12 bg-slate-900 border border-slate-700 rounded-xl px-4 text-white font-mono"
                                placeholder="0"
                            />
                        </div>
                        <button 
                            onClick={handleReport}
                            className="h-12 bg-indigo-600 hover:bg-indigo-500 text-white font-black rounded-xl uppercase text-xs tracking-widest transition-all active:scale-95 border-2 border-indigo-400 shadow-lg"
                        >
                            {t('erp_btn_send')}
                        </button>
                    </div>
                </div>
            )}

            {/* LIST OF BLOCKS */}
            <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
                {props.erpBlocks.length > 0 ? (
                    props.erpBlocks.map(block => {
                        const age = getAgeingMinutes(block.timestamp);
                        const isWaiting = block.status === 'WAITING';
                        const isResolving = block.status === 'RESOLVING';
                        const isReady = block.status === 'READY';
                        const isAddingComment = commentTargetId === block.id;

                        return (
                            <div key={block.id} className={`p-6 rounded-3xl border-2 transition-all relative overflow-hidden ${
                                isWaiting ? 'bg-rose-900/10 border-rose-500 animate-pulse' :
                                isResolving ? 'bg-amber-900/10 border-amber-500' :
                                'bg-emerald-900/10 border-emerald-500 opacity-80 shadow-inner'
                            }`}>
                                <div className="flex justify-between items-start mb-4 relative z-10">
                                    <div>
                                        <h4 className="text-2xl font-black font-mono text-white tracking-tighter">{block.partNumber}</h4>
                                        <p className="text-[10px] font-black text-slate-500 uppercase tracking-widest mt-1">
                                            {new Date(block.timestamp).toLocaleTimeString('sk-SK')}
                                        </p>
                                    </div>
                                    <div className="text-right">
                                        <span className={`text-[9px] font-black px-2 py-1 rounded border uppercase tracking-widest ${
                                            isWaiting ? 'bg-rose-500 text-white border-rose-400' :
                                            isResolving ? 'bg-amber-500 text-white border-amber-400' :
                                            'bg-emerald-500 text-white border-emerald-400'
                                        }`}>
                                            {t(`erp_status_${block.status.toLowerCase()}` as any)}
                                        </span>
                                        {!isReady && (
                                            <p className={`text-[10px] font-bold mt-2 ${age > 30 ? 'text-rose-500 animate-pulse' : 'text-slate-400'}`}>
                                                {t('erp_ageing', { min: age })}
                                            </p>
                                        )}
                                    </div>
                                </div>

                                {/* KOMENTÁROVÁ SEKICA */}
                                {block.comment && (
                                    <div className="bg-black/20 p-3 rounded-xl border border-white/5 mb-4 relative z-10">
                                        <p className="text-[8px] font-black text-slate-600 uppercase mb-1">POZNÁMKA ADMNA:</p>
                                        <p className="text-xs text-slate-300 italic">"{block.comment}"</p>
                                    </div>
                                )}

                                <div className="flex justify-between items-end relative z-10 border-t border-white/5 pt-4">
                                    <div>
                                        <p className="text-[9px] font-black text-slate-600 uppercase tracking-widest">HLÁSIL</p>
                                        <p className="text-xs font-bold text-slate-300 uppercase">{props.resolveName(block.reportedBy)}</p>
                                    </div>
                                    <div className="text-center bg-slate-900/50 px-4 py-2 rounded-xl border border-white/5 mx-4">
                                        <p className="text-[8px] font-black text-slate-600 uppercase mb-0.5">MNOŽSTVO</p>
                                        <p className="text-xl font-black text-indigo-400 font-mono">{block.quantity}</p>
                                    </div>

                                    <div className="flex gap-2">
                                        {props.hasPermission('perm_settings_system') && !isReady && (
                                            <>
                                                {isAddingComment ? (
                                                    <div className="flex flex-col gap-2 animate-fade-in min-w-[200px]">
                                                        <input 
                                                            autoFocus
                                                            value={tempComment}
                                                            onChange={e => setTempComment(e.target.value)}
                                                            placeholder="Pridať poznámku..."
                                                            className="bg-slate-950 border border-emerald-500/50 rounded-lg px-3 py-1.5 text-xs text-white outline-none"
                                                        />
                                                        <div className="flex gap-2">
                                                            <button onClick={() => { setCommentTargetId(null); setTempComment(''); }} className="flex-1 bg-slate-800 text-slate-400 py-1.5 rounded text-[10px] font-black">ZRUŠIŤ</button>
                                                            <button onClick={() => { props.onUpdateERPBlockStatus(block.id, 'READY', tempComment); setCommentTargetId(null); setTempComment(''); }} className="flex-1 bg-emerald-600 text-white py-1.5 rounded text-[10px] font-black shadow-lg">ODOSLAŤ</button>
                                                        </div>
                                                    </div>
                                                ) : (
                                                    <div className="flex gap-2">
                                                        {isWaiting && (
                                                            <button onClick={() => props.onUpdateERPBlockStatus(block.id, 'RESOLVING')} className="bg-amber-600 hover:bg-amber-500 text-white px-4 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all shadow-md">{t('erp_btn_process')}</button>
                                                        )}
                                                        <button onClick={() => setCommentTargetId(block.id)} className="bg-emerald-600 hover:bg-emerald-500 text-white px-4 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all shadow-md">{t('erp_btn_fix')}</button>
                                                    </div>
                                                )}
                                            </>
                                        )}
                                        {isReady && props.hasPermission('perm_manage_db') && (
                                            <button onClick={() => props.onDeleteERPBlock(block.id)} className="bg-slate-800 text-slate-500 px-3 py-2 rounded-lg hover:text-red-500 transition-all">🗑️</button>
                                        )}
                                    </div>
                                </div>
                            </div>
                        );
                    })
                ) : (
                    <div className="col-span-full py-20 text-center bg-slate-900/40 border-2 border-dashed border-slate-800 rounded-3xl">
                        <p className="text-slate-600 font-black uppercase tracking-[0.4em]">{t('erp_empty')}</p>
                    </div>
                )}
            </div>
        </div>
    );
};

