import React, { useState, useMemo } from 'react';
import { Task, PriorityLevel, DBItem, MapSector } from '../../types/appTypes';
import { useLanguage } from '../LanguageContext';
import TaskCard from './tasklist/TaskCard';
import TaskModals from './tasklist/TaskModals';
import SearchConfirmModal from '../modals/SearchConfirmModal';
import AuditModal from '../modals/AuditModal';
import SectorPickerModal from '../modals/SectorPickerModal';

interface TaskListProps {
  currentUser: 'ADMIN' | 'USER' | 'LEADER';
  currentUserName: string;
  tasks: Task[];
  missingReasons: DBItem[];
  mapSectors: MapSector[];
  onToggleTask: (id: string, sectorId?: string) => void;
  onEditTask: (id: string, updates: Partial<Task>) => void;
  onDeleteTask: (id: string) => void;
  onToggleMissing: (id: string, reason?: string) => void;
  onSetInProgress: (id: string) => void;
  onToggleBlock: (id: string) => void;
  onToggleManualBlock: (id: string) => void;
  onExhaustSearch: (id: string) => void;
  onMarkAsIncorrect: (id: string) => void;
  onAddNote: (id: string, note: string) => void;
  onReleaseTask: (id: string) => void;
  onAuditPart?: (id: string) => void;
  onFinishAudit?: (id: string, result: 'found' | 'missing', note: string) => void;
  hasPermission: (perm: string) => boolean;
  resolveName: (username?: string | null) => string;
}

const TaskList: React.FC<TaskListProps> = (props) => {
  const { t } = useLanguage();

  const [searchTerm, setSearchTerm] = useState('');
  const [priorityEditId, setPriorityEditId] = useState<string | null>(null);
  const [missingId, setMissingId] = useState<string | null>(null);
  const [noteId, setNoteId] = useState<string | null>(null);
  const [noteVal, setNoteVal] = useState('');
  const [deleteId, setDeleteId] = useState<string | null>(null);
  const [copiedId, setCopiedId] = useState<string | null>(null);

  const [searchConfirmTask, setSearchConfirmTask] = useState<Task | null>(null);
  const [auditTask, setAuditTask] = useState<Task | null>(null);
  const [pendingCompleteTask, setPendingCompleteTask] = useState<Task | null>(null);

  // --- LOKÁLNA FILTRÁCIA ---
  const filteredTasks = useMemo(() => {
    if (!searchTerm.trim()) return props.tasks;
    const q = searchTerm.toLowerCase().trim();
    return props.tasks.filter(task => 
      (task.partNumber || '').toLowerCase().includes(q) ||
      (task.workplace || '').toLowerCase().includes(q) ||
      (task.note || '').toLowerCase().includes(q)
    );
  }, [props.tasks, searchTerm]);

  const openPriorityModal = (task: Task) => {
    setPriorityEditId(task.id);
    setMissingId(null); setNoteId(null); setDeleteId(null);
  };

  const confirmPriority = (id: string, newPriority: PriorityLevel) => {
    const task = props.tasks.find(t => t.id === id);
    if (task) props.onEditTask(id, { priority: newPriority });
    setPriorityEditId(null);
  };

  const handleToggleTaskWithCheck = (id: string) => {
      const task = props.tasks.find(t => t.id === id);
      if (!task) return;

      // Ak je úloha hotová, vrátime ju (re-open) bez otázky na sektor
      if (task.isDone) {
          props.onToggleTask(id);
          return;
      }

      // Ak ide o VÝROBNÚ úlohu a nie je ešte hotová, pýtame sa skladníka odkiaľ ju vzal
      if (task.isProduction) {
          setPendingCompleteTask(task);
      } else {
          // Pre logistiku alebo iné typy uzavrieme okamžite
          props.onToggleTask(id);
      }
  };

  const confirmSectorPick = (sectorId: string) => {
      if (pendingCompleteTask) {
          props.onToggleTask(pendingCompleteTask.id, sectorId);
          setPendingCompleteTask(null);
      }
  };

  const handleSearchClick = (task: Task) => {
    if (!task.isBlocked) {
      props.onToggleBlock(task.id);
    } else {
      setSearchConfirmTask(task);
    }
  };

  const confirmSearch = (taskId: string, found: boolean) => {
    if (found) {
      props.onToggleMissing(taskId); // Reset missing
      props.onToggleBlock(taskId);  // Reset searching
    } else {
      props.onExhaustSearch(taskId); // Permanent unsuccessful search
      props.onToggleBlock(taskId);   // Reset searching status
    }
    setSearchConfirmTask(null);
  };

  const handleAuditClick = (task: Task) => {
    if (!task.isAuditInProgress) {
      props.onAuditPart?.(task.id);
    } else {
      setAuditTask(task);
    }
  };

  const handleMissingClick = (task: Task, e: React.MouseEvent) => {
    e.stopPropagation();
    if (task.isMissing) props.onToggleMissing(task.id);
    else {
      setMissingId(missingId === task.id ? null : task.id);
      setPriorityEditId(null); setNoteId(null); setDeleteId(null);
    }
  };

  const confirmMissing = (id: string, reason: string) => {
    props.onToggleMissing(id, reason);
    setMissingId(null);
  };

  const handleNoteClick = (task: Task) => {
    const isNoteLocked = !!(task.auditFinalBadge && !props.hasPermission('perm_btn_audit'));
    if (isNoteLocked) return;
    setNoteId(noteId === task.id ? null : task.id);
    setNoteVal(task.note || '');
    setPriorityEditId(null); setMissingId(null); setDeleteId(null);
  };

  const handleDeleteClick = (id: string) => {
    setDeleteId(id);
    setPriorityEditId(null); setMissingId(null); setNoteId(null);
  };

  const confirmDelete = () => {
    if (deleteId) {
      props.onDeleteTask(deleteId);
      setDeleteId(null);
    }
  };

  const handleCopyPart = (id: string, text: string) => {
    if (!text) return;
    navigator.clipboard.writeText(text).then(() => {
      setCopiedId(id);
      setTimeout(() => setCopiedId(null), 1500);
    }).catch(err => console.error('Copy failed', err));
  };

  const saveNote = (id: string) => {
    props.onAddNote(id, noteVal);
    setNoteId(null);
  };

  return (
    <div className="flex flex-col space-y-3 pb-20">
      {/* VYHĽADÁVACÍ PANEL */}
      <div className="sticky top-0 z-30 bg-gray-900/95 backdrop-blur-sm pb-4 pt-1">
        <div className="relative group">
          <input 
            type="text" 
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
            placeholder={t('task_search_placeholder')}
            className="w-full h-14 bg-gray-800 border-2 border-gray-700 rounded-2xl px-6 pl-14 text-white text-lg focus:outline-none focus:border-teal-500 focus:ring-4 focus:ring-teal-500/10 transition-all font-mono uppercase placeholder:text-gray-600 shadow-xl"
          />
          <div className="absolute left-5 top-4 text-gray-500 group-focus-within:text-teal-500 transition-colors">
            <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2.5}>
              <path strokeLinecap="round" strokeLinejoin="round" d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" />
            </svg>
          </div>
          {searchTerm && (
            <button 
              onClick={() => setSearchTerm('')}
              className="absolute right-4 top-3.5 p-1.5 bg-gray-700 hover:bg-gray-600 text-gray-400 hover:text-white rounded-lg transition-colors"
            >
              <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" viewBox="0 0 20 20" fill="currentColor">
                <path fillRule="evenodd" d="M4.293 4.293a1 1 0 011.414 0L10 8.586l4.293-4.293a1 1 0 111.414 1.414L11.414 10l4.293 4.293a1 1 0 01-1.414 1.414L10 11.414l-4.293 4.293a1 1 0 01-1.414-1.414L8.586 10 4.293 5.707a1 1 0 010-1.414z" clipRule="evenodd" />
              </svg>
            </button>
          )}
        </div>
      </div>

      {filteredTasks.length === 0 && (
        <div className="text-center py-20 text-gray-500 italic bg-gray-800/50 rounded-3xl border-2 border-dashed border-gray-700 animate-fade-in">
          <div className="mb-4 opacity-20 flex justify-center">
            <svg xmlns="http://www.w3.org/2000/svg" className="h-16 w-16" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1} d="M9.172 9.172a4 4 0 015.656 0M9 10h.01M15 10h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" />
            </svg>
          </div>
          <p className="text-xl font-bold uppercase tracking-tighter">{searchTerm ? 'Nič sa nenašlo' : t('empty_tasks')}</p>
          {searchTerm && <p className="text-sm mt-1">Skúste upraviť hľadaný výraz</p>}
        </div>
      )}

      {filteredTasks.map((task) => {
        const isSystemInventoryTask = task.partNumber === "Počítanie zásob";
        if (isSystemInventoryTask && !props.hasPermission('perm_tab_inventory')) return null;

        return (
          <TaskCard 
            key={task.id}
            task={task}
            currentUserName={props.currentUserName}
            isSystemInventoryTask={isSystemInventoryTask}
            copiedId={copiedId}
            hasPermission={props.hasPermission}
            onSetInProgress={props.onSetInProgress}
            onToggleTask={() => handleToggleTaskWithCheck(task.id)}
            onToggleBlock={() => handleSearchClick(task)}
            onToggleManualBlock={props.onToggleManualBlock}
            onExhaustSearch={props.onExhaustSearch}
            onMarkAsIncorrect={props.onMarkAsIncorrect}
            handleMissingClick={handleMissingClick}
            handleNoteClick={handleNoteClick}
            handleDeleteClick={handleDeleteClick}
            handleCopyPart={handleCopyPart}
            openPriorityModal={openPriorityModal}
            onAuditPart={() => handleAuditClick(task)}
            resolveName={props.resolveName}
          />
        );
      })}

      <TaskModals 
        priorityEditId={priorityEditId}
        missingId={missingId}
        noteId={noteId}
        deleteId={deleteId}
        noteVal={noteVal}
        missingReasons={props.missingReasons}
        tasks={props.tasks}
        setPriorityEditId={setPriorityEditId}
        setMissingId={setMissingId}
        setNoteId={setNoteId}
        setDeleteId={setDeleteId}
        setNoteVal={setNoteVal}
        confirmPriority={confirmPriority}
        confirmMissing={confirmMissing}
        saveNote={saveNote}
        confirmDelete={confirmDelete}
      />

      {searchConfirmTask && (
        <SearchConfirmModal 
          task={searchConfirmTask} 
          onClose={() => setSearchConfirmTask(null)} 
          onConfirm={confirmSearch} 
        />
      )}

      {auditTask && (
        <AuditModal 
          task={auditTask} 
          onClose={() => setAuditTask(null)} 
          onConfirm={(id, res, note) => {
            props.onFinishAudit?.(id, res, note);
            setAuditTask(null);
          }} 
        />
      )}

      {pendingCompleteTask && (
        <SectorPickerModal 
          task={pendingCompleteTask}
          mapSectors={props.mapSectors}
          onClose={() => setPendingCompleteTask(null)}
          onConfirm={confirmSectorPick}
        />
      )}
    </div>
  );
};

export default TaskList;

import { useState, useEffect, useRef } from 'react';
import { db } from '../../firebase';
import { 
  collection, 
  onSnapshot, 
  query, 
  where,
  limit,
  doc,
  addDoc,
  updateDoc,
  deleteDoc,
  writeBatch,
  getDocs,
  getDoc
} from 'firebase/firestore';
import { Task, PriorityLevel, Notification } from '../../types/appTypes';
import { PRIORITY_ORDER } from '../../constants/uiConstants';

const getISOWeekId = () => {
  const date = new Date();
  date.setHours(0, 0, 0, 0);
  date.setDate(date.getDate() + 3 - (date.getDay() + 6) % 7);
  const week1 = new Date(date.getFullYear(), 0, 4);
  const weekNumber = 1 + Math.round(((date.getTime() - week1.getTime()) / 86400000 - 3 + (week1.getDay() + 6) % 7) / 7);
  return `SANON_${date.getFullYear()}_${weekNumber.toString().padStart(2, '0')}`;
};

export const useTaskData = (
    isAuthenticated: boolean, 
    checkPermission: (perm: string) => boolean,
    onAddNotification: (n: Partial<Notification>) => void
) => {
  const [tasks, setTasks] = useState<Task[]>([]);
  const [draftTasks, setDraftTasks] = useState<Task[]>([]);
  const isFirstLoad = useRef(true);

  // --- LISTENER PRE ŽIVÉ ÚLOHY ---
  useEffect(() => {
    if (!isAuthenticated) return;
    const threshold = Date.now() - (3 * 24 * 60 * 60 * 1000); // 3 dni dozadu
    const q = query(collection(db, 'tasks'), where('createdAt', '>=', threshold), limit(300)); 

    return onSnapshot(q, (snapshot) => {
      const newTasks = snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as Task));

      // Zvuková notifikácia pre nové úlohy
      if (!isFirstLoad.current) {
          snapshot.docChanges().forEach((change) => {
              if (change.type === 'added') {
                  const task = change.doc.data() as Task;
                  if (task.createdAt && (Date.now() - task.createdAt < 10000)) {
                      if (checkPermission('perm_play_sound')) {
                          try {
                              const audio = new Audio('https://codeskulptor-demos.commondatastorage.googleapis.com/pang/pop.mp3');
                              audio.play().catch(e => console.log('Sound blocked', e));
                          } catch (e) {}
                      }
                  }
              }
          });
      }
      isFirstLoad.current = false;

      // Triedenie úloh
      const sortedTasks = newTasks.sort((a, b) => {
        if (a.isDone !== b.isDone) return a.isDone ? 1 : -1;
        if (a.isDone) {
            const timeA = a.completedAt || a.createdAt || 0;
            const timeB = b.completedAt || b.createdAt || 0;
            return timeB - timeA; 
        }
        const aManBlocked = a.isManualBlocked ? 1 : 0;
        const bManBlocked = b.isManualBlocked ? 1 : 0;
        if (aManBlocked !== bManBlocked) return aManBlocked - bManBlocked;
        const pA = PRIORITY_ORDER[a.priority || 'NORMAL'];
        const pB = PRIORITY_ORDER[b.priority || 'NORMAL'];
        if (pA !== pB) return pA - pB;
        return (a.createdAt || 0) - (b.createdAt || 0); 
      });
      setTasks(sortedTasks);
    });
  }, [isAuthenticated, checkPermission]);

  // --- LISTENER PRE DRAFT (Denný archív) ---
  useEffect(() => {
    const unsubDraft = onSnapshot(doc(db, 'settings', 'draft'), (s) => {
      if (s.exists()) {
        const d = s.data();
        setDraftTasks(Array.isArray(d.data) ? d.data : []);
      } else {
        setDraftTasks([]);
      }
    }, (err) => {
      console.error("Draft snapshot error:", err);
      setDraftTasks([]);
    });
    return () => unsubDraft();
  }, []);

  // --- ACTIONS ---

  // Inteligentné pridanie úlohy
  const onAddTask = async (
      partNumber: string, 
      workplace: string | null, 
      quantity: string | null, 
      quantityUnit: string | null, 
      priority: PriorityLevel, 
      isLogistics: boolean = false, 
      noteOrPlate: string = '', 
      isProduction: boolean = false,
      sourceSectorId?: string, 
      targetSectorId?: string
  ) => {
    const createdBy = localStorage.getItem('app_user') || 'Unknown';

    // 1. Špeciálny prípad: Inventúra
    if (partNumber === "Počítanie zásob") {
        try {
            await addDoc(collection(db, 'tasks'), {
                partNumber, 
                workplace: workplace || '', 
                quantity: quantity || '0', 
                quantityUnit: quantityUnit || 'pcs', 
                priority, 
                isLogistics, 
                note: noteOrPlate, 
                text: partNumber, 
                status: 'unpacked', 
                isInProgress: true, 
                inProgressBy: createdBy, 
                isDone: false, 
                isMissing: false, 
                createdAt: Date.now(), 
                createdBy: createdBy, 
                isProduction: !!isProduction
            });
        } catch (e) { console.error("Failed to create inventory task", e); }
        return;
    }

    // 2. Bežná úloha
    const newTask = {
        text: partNumber, 
        partNumber, 
        workplace: workplace || '', 
        quantity: quantity || '0', 
        quantityUnit: quantityUnit || 'pcs', 
        priority, 
        isLogistics, 
        isProduction, 
        note: isLogistics ? '' : noteOrPlate, // Ak logistika, note ide do plate
        plate: isLogistics ? noteOrPlate : '',
        isDone: false, 
        isMissing: false, 
        createdAt: Date.now(), 
        createdBy, 
        status: 'open',
        sourceSectorId: sourceSectorId || null,
        targetSectorId: targetSectorId || null
    };
    try { await addDoc(collection(db, 'tasks'), newTask); } catch (e) { console.error("Error adding task", e); }
  };

  const onUpdateTask = async (id: string, updates: Partial<Task>) => {
    try { await updateDoc(doc(db, 'tasks', id), updates); } catch(e) { console.error("Error updating task", e); }
  };

  const onDeleteTask = async (id: string) => {
    try { await deleteDoc(doc(db, 'tasks', id)); } catch(e) { console.error(e); }
  };

  const onToggleTask = async (id: string, sectorId?: string) => {
      const task = tasks.find(t => t.id === id);
      if(!task) return;
      const currentUser = localStorage.getItem('app_user') || 'Unknown';
      const updates: any = { isDone: !task.isDone };

      if (!task.isDone) { 
          updates.completedAt = Date.now(); 
          updates.completedBy = currentUser; 
          updates.status = 'completed'; 
          if (sectorId) {
              updates.pickedFromSectorId = sectorId;
          }
      } else { 
          updates.completedAt = null; 
          updates.completedBy = null; 
          updates.status = 'open'; 
          updates.isInProgress = false; 
          updates.inProgressBy = null; 
          updates.pickedFromSectorId = null;
      }
      await onUpdateTask(id, updates);
  };

  const onEditTask = async (id: string, newText: string, newPriority?: PriorityLevel) => {
    const updates: any = { text: newText, partNumber: newText };
    if (newPriority) updates.priority = newPriority;
    await onUpdateTask(id, updates);
  };

  const onToggleMissing = async (id: string, reason?: string) => {
    const task = tasks.find(t => t.id === id);
    if (!task) return;
    const user = localStorage.getItem('app_user') || 'Unknown';
    const updates: any = { isMissing: !task.isMissing };

    if (!task.isMissing) { 
        updates.missingReason = reason || 'Unknown'; 
        updates.missingReportedBy = user;
        // Ak sa nahlási missing, automaticky sa zastaví riešenie
        updates.isInProgress = false;
        updates.inProgressBy = null;

        // Notifikácia
        if (task.createdBy) {
            onAddNotification({ 
                partNumber: task.partNumber || 'Unknown', 
                reason: `CHÝBA: ${reason || 'Neuvedený dôvod'}`, 
                reportedBy: user, 
                targetUser: task.createdBy, 
                timestamp: Date.now() 
            });
        }
    } else { 
        updates.missingReason = null; 
        updates.missingReportedBy = null; 
    }
    await onUpdateTask(id, updates);
  };

  const onSetInProgress = async (id: string) => {
    const task = tasks.find(t => t.id === id);
    if (!task) return;
    const user = localStorage.getItem('app_user') || 'Unknown';
    if (task.isInProgress) await onUpdateTask(id, { isInProgress: false, inProgressBy: null });
    else await onUpdateTask(id, { isInProgress: true, inProgressBy: user, startedAt: Date.now() });
  };

  const onToggleBlock = async (id: string) => {
    const task = tasks.find(t => t.id === id);
    if (!task) return;
    const user = localStorage.getItem('app_user') || 'Unknown';
    if (task.isBlocked) await onUpdateTask(id, { isBlocked: false, blockedBy: null });
    else await onUpdateTask(id, { isBlocked: true, blockedBy: user, searchedBy: user });
  };

  const onToggleManualBlock = async (id: string) => {
    const task = tasks.find(t => t.id === id);
    if (!task) return;
    const newState = !task.isManualBlocked;
    const updates: any = { isManualBlocked: newState };

    // Ak sa blokuje, zrušíme InProgress a znížime prioritu
    if (newState) {
        updates.isInProgress = false;
        updates.inProgressBy = null;
        updates.priority = 'LOW';
    } else {
        // Pri odblokovaní obnovíme čas (aby to vyzeralo ako nová úloha)
        updates.createdAt = Date.now();
    }
    await onUpdateTask(id, updates);
  };

  const onExhaustSearch = async (id: string) => {
    await onUpdateTask(id, { searchExhausted: true });
  };

  const onMarkAsIncorrect = async (id: string) => {
    const user = localStorage.getItem('app_user') || 'Unknown';
    await onUpdateTask(id, { status: 'incorrectly_entered', isDone: true, completedBy: user, completedAt: Date.now(), isInProgress: false, inProgressBy: null });
  };

  const onAddNote = async (id: string, note: string) => {
    await onUpdateTask(id, { note });
  };

  const onReleaseTask = async (id: string) => {
    await onUpdateTask(id, { isBlocked: false, isManualBlocked: false, isInProgress: false, inProgressBy: null, blockedBy: null });
  };

  // --- AUDIT LOGIC ---

  const onStartAudit = async (id: string) => {
      const user = localStorage.getItem('app_user') || 'Unknown';
      await onUpdateTask(id, { 
          isAuditInProgress: true, 
          auditBy: user, 
          isInProgress: false, 
          inProgressBy: null 
      });
  };

  const onFinishAudit = async (id: string, result: 'found' | 'missing', note: string) => {
      const user = localStorage.getItem('app_user') || 'Unknown';
      const task = tasks.find(t => t.id === id);
      if (!task) return;

      const badgeText = result === 'found' ? `AUDIT (OK) - ${note}` : `AUDIT (NOK) - ${note}`;
      const updates: any = { 
          isAuditInProgress: false, 
          auditFinalBadge: badgeText, 
          auditBy: null, 
          auditResult: result === 'found' ? 'OK' : 'NOK', 
          auditNote: note, 
          auditedBy: user, 
          auditedAt: Date.now() 
      };

      if (result === 'found') { 
          updates.isMissing = false; 
      } else { 
          updates.isDone = true; 
          updates.status = 'audit_error'; 
          updates.completedBy = user; 
          updates.completedAt = Date.now(); 
          updates.isInProgress = false; 
      }

      await onUpdateTask(id, updates);

      // Notifikácia pre zadávateľa
      if (task.createdBy) {
          onAddNotification({ 
              partNumber: task.partNumber || 'Unknown', 
              reason: `AUDIT: ${result.toUpperCase()} - ${note}`, 
              reportedBy: user, 
              targetUser: task.createdBy, 
              timestamp: Date.now() 
          });
      }
  };

  // --- CLOSING & MAINTENANCE ---

  const onDailyClosing = async () => {
    try {
      const tasksRef = collection(db, 'tasks');
      const q = query(tasksRef, where('isDone', '==', true));
      const snapshot = await getDocs(q);
      if (snapshot.empty) return { success: true, count: 0 };
      const completedTasks = snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() }));
      const draftRef = doc(db, 'settings', 'draft');
      const draftSnap = await getDoc(draftRef);
      let existingData = [];
      if (draftSnap.exists()) existingData = draftSnap.data().data || [];
      const mergedData = [...existingData, ...completedTasks];
      const batch = writeBatch(db);
      batch.set(draftRef, { data: mergedData }, { merge: true });
      snapshot.docs.forEach((doc) => { batch.delete(doc.ref); });
      await batch.commit();
      return { success: true, count: completedTasks.length };
    } catch (e) { console.error("Daily closing failed:", e); return { success: false, count: 0 }; }
  };

  const onWeeklyClosing = async () => {
    try {
        const sanonId = getISOWeekId();
        const draftRef = doc(db, 'settings', 'draft');
        const draftSnap = await getDoc(draftRef);
        let draftTasksFromDb = [];
        if (draftSnap.exists()) draftTasksFromDb = draftSnap.data().data || [];
        const tasksRef = collection(db, 'tasks');
        const q = query(tasksRef, where('isDone', '==', true));
        const activeSnap = await getDocs(q);
        const activeTasks = activeSnap.docs.map(doc => ({ id: doc.id, ...doc.data() }));
        const allTasksToArchive = [...draftTasksFromDb, ...activeTasks];
        if (allTasksToArchive.length === 0) return { success: true, count: 0, sanon: sanonId };
        let batch = writeBatch(db);
        let opCount = 0;
        const sanonRef = doc(db, 'sanony', sanonId);
        batch.set(sanonRef, { tasks: allTasksToArchive, createdAt: Date.now(), id: sanonId });
        opCount++;
        batch.set(draftRef, { data: [] });
        opCount++;
        const docsToDelete = activeSnap.docs;
        for (let i = 0; i < docsToDelete.length; i++) {
            batch.delete(docsToDelete[i].ref);
            opCount++;
            if (opCount >= 498) { await batch.commit(); batch = writeBatch(db); opCount = 0; }
        }
        if (opCount > 0) await batch.commit();
        return { success: true, count: allTasksToArchive.length, sanon: sanonId };
    } catch (e) { console.error("Weekly closing failed:", e); return { success: false, count: 0, sanon: '' }; }
  };

  const fetchSanons = async () => {
      try {
          const snap = await getDocs(collection(db, 'sanony'));
          return snap.docs.map(d => ({ id: d.id, ...d.data() } as any));
      } catch (e) { console.error("Error fetching sanons", e); return []; }
  };

  return {
    tasks, draftTasks,
    onAddTask, onUpdateTask, onDeleteTask, onToggleTask, onEditTask, onToggleMissing,
    onSetInProgress, onToggleBlock, onToggleManualBlock, onExhaustSearch, 
    onMarkAsIncorrect, onAddNote, onReleaseTask,
    onStartAudit, onFinishAudit,
    onDailyClosing, onWeeklyClosing, fetchSanons
  };
};
